  .cover-tag::before { content: ''; width: 6px; height: 6px; background: #C5F010; border-radius: 50%; display: inline-block; }
  .cover-title { font-size: 72px; font-weight: 500; line-height: 1.05; letter-spacing: -2px; color: #ffffff; width: 100%; margin-top: 28px; }
  .cover-body { font-size: 22px; font-weight: 400; line-height: 1.6; color: rgba(255,255,255,0.6); margin-top: 40px; max-width: 560px; flex: 1; }
  .footer { display: flex; align-items: center; justify-content: space-between; margin-top: auto; padding-top: 24px; border-top: 1px solid rgba(255,255,255,0.07); }
  .author { display: flex; align-items: center; gap: 14px; }
  .author-info .by { font-size: 12px; color: rgba(255,255,255,0.35); line-height: 1; margin-bottom: 3px; }
  .author-info .name { font-size: 18px; font-weight: 700; color: rgba(255,255,255,0.88); line-height: 1; }
  .progress-dots { display: flex; gap: 6px; align-items: center; }
  .dot { width: 6px; height: 6px; border-radius: 50%; background: rgba(255,255,255,0.18); }
  .dot.active { width: 20px; border-radius: 3px; background: #C5F010; }
</style>
</head>
<body>
<div class="slide">
  <div class="bg"></div>
  <div class="line-accent"></div>
  <div class="inner">
    <div class="header-row">
      <svg width="52" height="52" viewBox="0 0 83 83" fill="none"><path d="M0 41.5C20.75 41.5 41.5 20.75 41.5 0C41.5 20.75 62.25 41.5 83 41.5C62.25 41.5 41.5 62.25 41.5 83C41.5 62.25 20.75 41.5 0 41.5Z" fill="#C5F010"/></svg>
      <span class="slide-counter">01 / ${String(totalSlides).padStart(2, '0')}</span>
    </div>
    <div class="cover-tag">${slide.cta || totalSlides + ' things to know'}</div>
    <div class="cover-title">${slide.title}</div>
    <div class="cover-body">${slide.body}</div>
    <div class="footer">
      <div class="author">
        <div class="author-info">
          <div class="by">By</div>
          <div class="name">Bara Adwan</div>
        </div>
      </div>
      <div class="progress-dots">${dots}</div>
    </div>
  </div>
</div>
</body>
</html>`;

  return [{
    json: {
      html,
      slideNumber: 1,
      totalSlides,
      title: slide.title,
      subtitle: slide.cta,
      post_text: parsed.post_text,
      isFirstSlide: true,
      isLastSlide: false
    }
  }];

} catch (error) {
  return [{
    json: {
      error: error.message,
      rawInput: $input.first().json.output[0].content[0].text
    }
  }];
}
