// Collect all input items (one item per connected upload node)
const inputs = $input.all();

// Map to array of objects CraftMyPdf expects: { url: "https://..." }
const urls = inputs.map(item => {
  // prefer webViewLink, fallback to constructing a Drive view link from id
  const webView = item.json.webViewLink || (item.json.id ? `https://drive.google.com/file/d/${item.json.id}/view` : null);
  return { url: webView };
}).filter(u => u.url); // drop any missing links

// Output a single item whose json.urls is the array
return [{ json: { urls } }];

const afterImageUrl = $input.first().json.AfterImageUrl;
const beforeImageUrl = $input.last().json.BeforeImageUrl;

const html = '<!DOCTYPE html>' +
'<html lang="en"><head><meta charset="UTF-8"><style>' +
