      companyName
    }
  };
});

return items.map(item => {
  const email = $input.first().json.properties.email || '';

  // Extract domain after @
  const domain = email.split('@')[1] || '';

  // Build https link
  const website = domain ? `https://${domain}` : '';

  return {
    json: {
      website
    }
  };
});

// Require images Code node
// If either image URL is missing, return [] to stop the rest of the workflow.

const after = $input.first().json.AfterImageUrl;
const before = $input.last().json.BeforeImageUrl;

// If either is falsy (undefined, null, empty string), stop here
if (!after || !before) {
  // Optional: set a useful output for logs or Slack if you want:
  // return [{ json: { stopped: true, reason: 'Missing image(s)' } }];
  return []; // returning no items prevents downstream nodes from running
}

// Both images exist — continue the normal flow
return items;

const orderJsonKeys = (jsonObj) => {
  const ordered = {};
  Object.keys(jsonObj).sort().forEach(key => {
    ordered[key] = jsonObj[key];
  });
  return ordered;
}

// Check if file returned with content
if (Object.keys($input.all()[0].json).includes("content")) {
  // Decode base64 content and parse JSON
  const origWorkflow = JSON.parse(Buffer.from($input.all()[0].json.content, 'base64').toString());
  const n8nWorkflow = $input.all()[1].json;

  // Order JSON objects
  const orderedOriginal = orderJsonKeys(origWorkflow);
  const orderedActual = orderJsonKeys(n8nWorkflow);

  // Determine difference
  if (JSON.stringify(orderedOriginal) === JSON.stringify(orderedActual)) {
    $input.all()[0].json.github_status = "same";
  } else {
    $input.all()[0].json.github_status = "different";
    $input.all()[0].json.n8n_data_stringy = JSON.stringify(orderedActual, null, 2);
