// Generate ISO 8601 timestamp with local timezone offset (e.g. +03:00)
const date = new Date();
const tzOffset = -date.getTimezoneOffset();
const diff = tzOffset >= 0 ? '+' : '-';
const pad = (n) => String(Math.floor(Math.abs(n))).padStart(2, '0');
const offset = `${diff}${pad(tzOffset / 60)}:${pad(tzOffset % 60)}`;

const formatted = date.toISOString().replace('Z', offset);

return [
  {
    json: {
      timestamp: formatted
    }
  }
];

// Filter & Pick 96h Lead - n8n Function node (runOnceForAllItems)
// Input: items from "Search contacts" (each item.json is a contact with .id and .properties)
// Output: single chosen contact item (same shape as incoming) or [] if none eligible

const items = $input.all();
if (!items.length) return [];

// now timestamp (ms)
const nowTs = Date.now();
const ms96h = 96 * 60 * 60 * 1000; // 96 hours gap

// helper to safely read property values (handles nested { value: ... } shapes)
function readProp(props, keyVariants) {
  if (!props) return null;
  for (const k of keyVariants) {
    if (Object.prototype.hasOwnProperty.call(props, k)) {
      const v = props[k];
      if (v && typeof v === 'object' && Object.prototype.hasOwnProperty.call(v, 'value')) return v.value;
      return v;
    }
  }
  return null;
}

// Normalize truthy checks of booleans stored as strings
function isTrue(val) {
  if (val === true) return true;
  if (typeof val === 'string') {
    const s = val.toLowerCase().trim();
    return s === 'true' || s === '1' || s === 'yes';
  }
  if (typeof val === 'number') return val === 1;
  return false;
}

// Collect eligible contacts
const eligible = [];

for (const it of items) {
  const contact = it.json || {};
  const props = contact.properties || contact;

  // Pull Last Email Date (your field). Try a few possible keys.
  const lastRaw = readProp(props, ["Last Email Date", "last_email_date", "lastemaildate", "last_email_date.value", "last_email_date_value"]);

  // If lastRaw missing -> ALLOW the contact (run the workflow for it).
  let lastMissing = false;
  if (!lastRaw) {
    lastMissing = true;
  }

  // If lastRaw exists, parse it and enforce 96h gap. If it's missing, bypass the check.
  if (!lastMissing) {
    const lastTs = Date.parse(String(lastRaw));
    if (isNaN(lastTs)) continue;

    const diff = nowTs - lastTs;
    if (diff < ms96h) continue; // under 96 hours -> skip
  }

  // followup_active must be true
  const followupActiveRaw = readProp(props, ["follow_up", "followup_active", "follow_up_active"]);
  if (!isTrue(followupActiveRaw)) continue;

  // Check Form Submitted must be false
  const formSubmittedRaw = readProp(props, ["form_submitted", "Check Form Submitted", "check_form_submitted"]);
  if (isTrue(formSubmittedRaw)) continue;

  // follow_up_stage must be > 0
  const stageRaw = readProp(props, ["follow_up_stage", "followup_stage", "followupStage"]);
  let stageNum = null;
  if (stageRaw !== undefined && stageRaw !== null) {
    stageNum = Number(stageRaw);
    if (isNaN(stageNum)) {
      const m = String(stageRaw).match(/\d+/);
      if (m) {
        stageNum = Number(m[0]);
      } else {
        continue;
      }
    }
  }
  if (stageNum === null || stageNum <= 0) continue;

  // NEW: Stop followups if follow_up_count is 10 or higher
  const followUpCountRaw = readProp(props, ["follow_up_count", "Follow Up Count"]);
  const followUpCount = followUpCountRaw !== null ? Number(followUpCountRaw) : 0;
  if (followUpCount >= 10) continue;

  eligible.push(it);
}

// return the first eligible contact (or empty array)
return eligible.length ? [eligible[0]] : [];

